import React from "react";

const Education = () => {
  return (
    <section id="education" className="py-20 px-6 bg-purple-50">
      <h2 className="text-3xl font-bold text-center mb-8">Education</h2>
      <div className="max-w-3xl mx-auto bg-white shadow p-6 rounded-lg">
        <h3 className="text-xl font-semibold text-purple-700">
          Bachelor of Computer Science
        </h3>
        <p className="text-gray-600">Dalhousie University (2021 – 2025)</p>
        <p className="mt-2 text-gray-700">
          Relevant Coursework: Operating Systems, Database Management, Systems
          Programming, Cloud Computing, IT Service Management, Software Engineering
        </p>
      </div>
    </section>
  );
};

export default Education;
